import React, { useState, useEffect } from "react";
import "../navbar.css";
import Lottie from "lottie-react";
import twitchAnimation from '../assets/twitch-live.json';
import kickAnimation from '../assets/kick-live.json';
import logoImage from "../assets/logo.gif";

function Navbar(props) {
  const [active, setActive] = useState("nav__menu");
  const [toggleIcon, setToggleIcon] = useState("nav__toggler");
  const [isKickLive, setIsKickLive] = useState(false);
  const [isTwitchLive, setIsTwitchLive] = useState(false);

  const navToggle = () => {
    active === 'nav__menu' ? setActive('nav__menu nav__active') : setActive('nav__menu');
    toggleIcon === 'nav__toggler' ? setToggleIcon('nav__toggler toggle') : setToggleIcon('nav__toggler');
  };

  const loadLiveStatus = () => {
    if (window.liveStatus && 'isTwitchLive' in window.liveStatus && 'isKickLive' in window.liveStatus) {
      const liveStatus = window.liveStatus;
      setIsTwitchLive(liveStatus.isTwitchLive);
      setIsKickLive(liveStatus.isKickLive);
    }
  };

  useEffect(() => {
    loadLiveStatus();
  }, []);

  const streamLink = isTwitchLive ? "https://www.twitch.tv/lannce" : "https://kick.com/BTCs";

  const handleStreamClick = () => {
    if (isTwitchLive || isKickLive) {
      window.location.href = streamLink;
    } else {
      alert("Stream is currently offline");
    }
  };
  
  
  return (
    <nav className='nav'>
      <a href="#" className="nav__brand" id="lance"><img src={logoImage} alt="Logo" />Lance x BTCs</a>
      <ul className={active}>
        <li className="nav__item" id="live">
          {isTwitchLive && <div className="animation__container"><Lottie animationData={twitchAnimation} /></div>}
          {isKickLive && <div className="animation__container"><Lottie animationData={kickAnimation} /></div>}
          <a href="#" className="nav__link" onClick={handleStreamClick}> Stream</a>
        </li>
        <li className="nav__item"><a href="https://www.btcs.gg/leaderboard/" className="nav__link">BTCs Leaderboard</a></li>
        <li className="nav__item"><a href="https://gamdom.com/r/btcs" className="nav__link">Gamdom</a></li>
        <li className="nav__item"><a href="mailto:lance@btcs.gg" className="nav__link">Contact</a></li>
        <li className="nav__item"><a href="https://twitter.com/ttvLannce" className="nav__link">Twitter/X</a></li>
        <li className="nav__item"><a href="https://discord.gg/rnAK9y6SdU" className="nav__link">Discord</a></li>
      </ul>
      <div onClick={navToggle} className={toggleIcon}>
        <div className="line1"></div>
        <div className="line2"></div>
        <div className="line3"></div>
      </div>
    </nav>
  );
}

export default Navbar;
